fn cmd_term_install(url: &str, prefix: &std::path::Path) -> Result<()> {
    use std::io::Write as _;
    use std::os::unix::fs::PermissionsExt as _;

    std::fs::create_dir_all(prefix)
        .with_context(|| format!("cannot create prefix directory {}", prefix.display()))?;

    let dest = prefix.join("smedja");
    println!("Downloading smedja from {url} ...");

    let bytes = reqwest::blocking::get(url)
        .with_context(|| format!("download failed: {url}"))?
        .bytes()
        .with_context(|| "failed to read response bytes")?;

    let mut file = std::fs::File::create(&dest)
        .with_context(|| format!("cannot create {}", dest.display()))?;
    file.write_all(&bytes)
        .with_context(|| format!("cannot write {}", dest.display()))?;

    std::fs::set_permissions(&dest, std::fs::Permissions::from_mode(0o755))
        .with_context(|| format!("cannot chmod +x {}", dest.display()))?;

    println!("Installed smedja to {}", dest.display());

    // On Linux, write a .desktop file.
    if std::env::consts::OS == "linux" {
        if let Ok(home) = std::env::var("HOME") {
            let apps_dir = PathBuf::from(&home).join(".local/share/applications");
            let _ = std::fs::create_dir_all(&apps_dir);
            let desktop_path = apps_dir.join("smedja.desktop");
            let desktop = format!(
                "[Desktop Entry]\nVersion=1.0\nType=Application\nName=smedja\nExec={}\nIcon=utilities-terminal\nTerminal=false\nCategories=System;TerminalEmulator;\n",
                dest.display()
            );
            if let Ok(mut f) = std::fs::File::create(&desktop_path) {
                let _ = f.write_all(desktop.as_bytes());
                println!("Registered {}", desktop_path.display());
            }
        }
    }

    Ok(())
}

/// Initialises a smedja workspace at the given directory.
///
/// Creates `.smedja/` and writes a `workspace.toml` with `auto_index = true`
/// and the current timestamp. Symbol indexing is performed separately via the
/// daemon's `graph.index` RPC by the caller.
fn cmd_workspace_init(dir: &std::path::Path) -> Result<()> {
    use chrono::Utc;
    let smedja_dir = dir.join(".smedja");
    std::fs::create_dir_all(&smedja_dir)?;
    let toml_path = smedja_dir.join("workspace.toml");
    let ts = Utc::now().to_rfc3339();
    let content = format!("[graph]\nauto_index = true\nlast_indexed_at = \"{ts}\"\n");
    std::fs::write(&toml_path, content)?;
    println!("Initialized workspace at {}", dir.display());
    Ok(())
}

/// Runs a workspace posture scan and prints the advisory findings.
///
/// The scan is advisory: it reports findings but blocks nothing. A clean
/// workspace prints a short confirmation.
fn cmd_security_scan(workspace: &std::path::Path) {
    let findings = smedja_security::scan_posture(workspace);
    if findings.is_empty() {
        println!("No posture findings in {}", workspace.display());
        return;
    }
    println!("{:<14} {:<10} MESSAGE", "RULE", "SEVERITY");
    println!("{}", "-".repeat(72));
    for f in &findings {
        println!(
            "{:<14} {:<10} {}",
            f.rule_id,
            f.severity.as_str(),
            f.message
        );
    }
    println!(
        "\n{} advisory finding(s) — these do not block any action",
        findings.len()
    );
}

/// Summarises recorded `security_finding` audit events as a read-only query.
fn cmd_security_report(ingot: &Ingot) -> Result<()> {
    let events = ingot
        .list_all_audit_events()
        .context("list_all_audit_events failed")?;
    let findings: Vec<_> = events
        .iter()
        .filter(|e| e.action_type == "security_finding")
        .collect();
    if findings.is_empty() {
        println!("No security findings recorded.");
        return Ok(());
    }
    println!("{:<14} {:<10} {:<8} SESSION", "RULE", "SEVERITY", "STATUS");
    println!("{}", "-".repeat(72));
    for e in &findings {
        println!(
            "{:<14} {:<10} {:<8} {}",
            e.tool_name.as_deref().unwrap_or("-"),
            e.error_kind.as_deref().unwrap_or("-"),
            e.status.as_deref().unwrap_or("-"),
            e.session_id,
        );
    }
    println!("\n{} recorded finding(s)", findings.len());
    Ok(())
}

/// Emits a CycloneDX-style SBOM for `lockfile` to stdout.
fn cmd_security_sbom(lockfile: &std::path::Path) -> Result<()> {
    let sbom = smedja_security::Sbom::from_lockfile(lockfile)
        .with_context(|| format!("failed to assemble SBOM from {}", lockfile.display()))?;
    let json = sbom.to_json().context("failed to serialise SBOM")?;
    println!("{json}");
    Ok(())
}

/// Builds the `audit.run` RPC params from the parsed `smj audit run` flags.
///
/// Scope precedence mirrors the daemon's `resolve_scope`: `--pr` → `--branch` →
/// `--diff`/no-path → a positional `<path>`.
fn build_audit_params(
    path: Option<&str>,
    branch: Option<&str>,
    pr: Option<&str>,
    diff: bool,
    report: Option<&str>,
    format: &str,
    workspace: Option<&str>,
) -> serde_json::Value {
    let mut params = json!({ "format": format });
    if let Some(pr) = pr {
        params["pr"] = json!(pr);
    } else if let Some(base) = branch {
        params["branch"] = json!(base);
    } else if diff {
        params["diff"] = json!(true);
    } else if let Some(path) = path {
        params["path"] = json!(path);
    }
    if let Some(report) = report {
        params["report"] = json!(report);
    }
    if let Some(ws) = workspace {
        params["workspace"] = json!(ws);
    }
    params
}

/// Parses a duration string (`7d`, `24h`, `30m`, `90s`, or bare seconds) into a
/// micros-since-epoch lower bound relative to `now_micros`.
///
/// A bare integer is interpreted as seconds. The result is `now_micros` minus
/// the parsed span, clamped at zero.
///
/// # Errors
///
/// Returns an error when the string is not a recognised duration.
fn since_to_micros(spec: &str, now_micros: i64) -> Result<i64> {
    let span_micros = duration_to_micros(spec)?;
    Ok(now_micros.saturating_sub(span_micros).max(0))
}

/// Parses a duration string into a span in microseconds.
///
/// Accepts a trailing unit suffix `d`/`h`/`m`/`s`; a bare integer is seconds.
fn duration_to_micros(spec: &str) -> Result<i64> {
    let spec = spec.trim();
    let (value_str, unit_secs) = match spec.chars().last() {
        Some('d') => (&spec[..spec.len() - 1], 86_400),
        Some('h') => (&spec[..spec.len() - 1], 3_600),
        Some('m') => (&spec[..spec.len() - 1], 60),
        Some('s') => (&spec[..spec.len() - 1], 1),
        _ => (spec, 1),
    };
    let value: i64 = value_str
        .parse()
        .with_context(|| format!("invalid duration: {spec}"))?;
    Ok(value.saturating_mul(unit_secs).saturating_mul(1_000_000))
}

/// Builds the `metrics.summary` request params from CLI flags.
///
/// `until` is omitted from the params when `None`, letting the daemon default it
/// to the current time.
fn build_metrics_params(
    tier: &str,
    since_micros: i64,
    until_micros: Option<i64>,
) -> serde_json::Value {
    let mut params = json!({ "tier": tier, "since": since_micros });
    if let Some(until) = until_micros {
        params["until"] = json!(until);
    }
    params
}

/// Renders the `metrics.summary` response into table rows, one per bucket,
/// optionally filtered to a single `runner`.
///
/// Returns the header line followed by one formatted line per bucket. The cost
/// column is the USD `f64` the daemon already converted at its display boundary.
fn format_metrics_rows(resp: &serde_json::Value, runner_filter: Option<&str>) -> Vec<String> {
    let mut lines = vec![format!(
        "{:<22}  {:<12}  {:>5}  {:>9}  {:>9}  {:>11}  {:>6}",
        "BUCKET", "RUNNER", "TURNS", "INPUT", "OUTPUT", "COST", "ERRORS"
    )];
    let Some(buckets) = resp["buckets"].as_array() else {
        return lines;
    };
    for b in buckets {
        let runner = b["runner"].as_str().unwrap_or("-");
        if let Some(filter) = runner_filter {
            if runner != filter {
                continue;
            }
        }
        let bucket = format_bucket_start(b["bucket_start"].as_i64().unwrap_or(0));
        let turns = b["turns"].as_i64().unwrap_or(0);
        let input = b["input_tok"].as_i64().unwrap_or(0);
        let output = b["output_tok"].as_i64().unwrap_or(0);
        let cost = b["cost_usd"].as_f64().unwrap_or(0.0);
        let errors = b["error_count"].as_i64().unwrap_or(0);
        lines.push(format!(
            "{bucket:<22}  {runner:<12}  {turns:>5}  {input:>9}  {output:>9}  ${cost:>10.6}  {errors:>6}"
        ));
    }
    lines
}

/// Formats a micros-since-epoch bucket start as a UTC `YYYY-MM-DD HH:MM` label.
fn format_bucket_start(micros: i64) -> String {
    chrono::DateTime::from_timestamp_micros(micros).map_or_else(
        || micros.to_string(),
        |dt| dt.format("%Y-%m-%d %H:%M").to_string(),
    )
}

/// Resolves a path to its SKILL.md content and the skill name from frontmatter.
fn read_skill_file(path: &std::path::Path) -> Result<(String, String)> {
    let skill_md = if path.is_dir() {
        path.join("SKILL.md")
    } else {
        path.to_owned()
    };
    let content = std::fs::read_to_string(&skill_md)
        .with_context(|| format!("cannot read {}", skill_md.display()))?;
    let skill = smedja_plugins::parse_skill(&content, &skill_md)
        .with_context(|| format!("invalid frontmatter in {}", skill_md.display()))?;
    Ok((skill.manifest.name, content))
}

#[cfg(test)]
mod tests {
    use super::*;

    // --- smj metrics ---

    #[test]
    fn metrics_parses_subcommand_with_flags() {
        let cli = Cli::try_parse_from([
            "smj", "metrics", "--tier", "hourly", "--since", "24h", "--runner", "claude", "--json",
        ])
        .expect("metrics must parse");
        match cli.command {
            Cmd::Metrics {
                tier,
                since,
                until,
                runner,
                json,
            } => {
                assert_eq!(tier, "hourly");
                assert_eq!(since, "24h");
                assert_eq!(until, None);
                assert_eq!(runner.as_deref(), Some("claude"));
                assert!(json);
            }
            _ => panic!("expected Cmd::Metrics"),
        }
    }

    #[test]
    fn metrics_tier_defaults_to_daily() {
        let cli = Cli::try_parse_from(["smj", "metrics"]).expect("metrics must parse");
        match cli.command {
            Cmd::Metrics { tier, since, .. } => {
                assert_eq!(tier, "daily");
                assert_eq!(since, "7d");
            }
            _ => panic!("expected Cmd::Metrics"),
        }
    }

    #[test]
    fn since_to_micros_subtracts_duration() {
        // now = 1_000_000s in micros; 1d back = 86_400s earlier.
        let now = 1_000_000_000_000;
        assert_eq!(since_to_micros("1d", now).unwrap(), now - 86_400_000_000);
        assert_eq!(since_to_micros("2h", now).unwrap(), now - 7_200_000_000);
        assert_eq!(since_to_micros("30m", now).unwrap(), now - 1_800_000_000);
        assert_eq!(since_to_micros("45s", now).unwrap(), now - 45_000_000);
        // Bare integer is seconds.
        assert_eq!(since_to_micros("10", now).unwrap(), now - 10_000_000);
    }

    #[test]
    fn since_to_micros_clamps_at_zero() {
        assert_eq!(since_to_micros("100d", 0).unwrap(), 0);
    }

    #[test]
    fn since_to_micros_rejects_garbage() {
        assert!(since_to_micros("notaduration", 0).is_err());
    }

    #[test]
    fn build_metrics_params_omits_until_when_absent() {
        let p = build_metrics_params("daily", 123, None);
        assert_eq!(p["tier"], "daily");
        assert_eq!(p["since"], 123);
        assert!(p.get("until").is_none());
        let p2 = build_metrics_params("hourly", 1, Some(999));
        assert_eq!(p2["until"], 999);
    }

    #[test]
    fn format_metrics_rows_renders_known_response() {
        // 2026-01-01 00:00:00 UTC = 1_767_225_600_000_000 micros.
        let resp = json!({
            "tier": "daily",
            "buckets": [
                {
                    "bucket_start": 1_767_225_600_000_000_i64,
                    "runner": "claude",
                    "turns": 3,
                    "input_tok": 600,
                    "output_tok": 180,
                    "cost_usd": 0.06,
                    "error_count": 1
                },
                {
                    "bucket_start": 1_767_225_600_000_000_i64,
                    "runner": "local",
                    "turns": 1,
                    "input_tok": 400,
                    "output_tok": 80,
                    "cost_usd": 0.0,
                    "error_count": 0
                }
            ]
        });
        let rows = format_metrics_rows(&resp, None);
        assert_eq!(rows.len(), 3, "header + two buckets");
        assert!(rows[0].contains("BUCKET") && rows[0].contains("ERRORS"));
        assert!(rows[1].contains("2026-01-01 00:00"));
        assert!(rows[1].contains("claude"));
        assert!(rows[1].contains("$  0.060000"));
        assert!(rows[2].contains("local"));

        // Runner filter keeps only the matching bucket.
        let filtered = format_metrics_rows(&resp, Some("claude"));
        assert_eq!(filtered.len(), 2, "header + claude only");
        assert!(filtered[1].contains("claude"));
    }

    // --- smj sandbox status ---

    #[test]
    fn sandbox_status_parses_subcommand() {
        let cli =
            Cli::try_parse_from(["smj", "sandbox", "status"]).expect("sandbox status must parse");
        assert!(matches!(
            cli.command,
            Cmd::Sandbox {
                action: SandboxCmd::Status
            }
        ));
    }

    #[test]
    fn sandbox_status_reports_backend_and_policy() {
        // Mode parsing covers the fallback-mode column.
        assert_eq!(SandboxStatus::mode_from_value("required"), "required");
        assert_eq!(SandboxStatus::mode_from_value("off"), "off");
        assert_eq!(SandboxStatus::mode_from_value(""), "auto");
        assert_eq!(SandboxStatus::mode_from_value("nonsense"), "auto");

        // Network policy parsing covers the network-policy column.
        assert_eq!(SandboxStatus::network_from_value("allowlist"), "allowlist");
        assert_eq!(SandboxStatus::network_from_value("open"), "open");
        assert_eq!(SandboxStatus::network_from_value(""), "none");

        // The resolved status reports a backend name, an availability flag, the
        // network policy, and the fallback mode for the current host.
        let status = SandboxStatus::detect();
        assert!(
            matches!(status.backend, "docker" | "seatbelt" | "landlock" | "none"),
            "backend must be one of the known names; got {}",
            status.backend
        );
        assert!(matches!(status.mode, "auto" | "required" | "off"));
        assert!(matches!(
            status.network_policy,
            "none" | "allowlist" | "open"
        ));
        // `available` is a bool by construction; assert it is consistent with
        // the "none" backend never being available.
        if status.backend == "none" {
            assert!(!status.available);
        }
    }

    // --- smj audit run parsing + params ---

    #[test]
    fn audit_run_parses_path_branch_pr_diff_report_format() {
        let cli = Cli::try_parse_from([
            "smj",
            "audit",
            "run",
            "src/lib.rs",
            "--report",
            "out.md",
            "--format",
            "json",
        ])
        .expect("audit run with a path must parse");
        let Cmd::Audit {
            action:
                AuditCmd::Run {
                    path,
                    branch,
                    pr,
                    diff,
                    report,
                    format,
                },
        } = cli.command
        else {
            panic!("expected an audit run command");
        };
        assert_eq!(path.as_deref(), Some("src/lib.rs"));
        assert_eq!(branch, None);
        assert_eq!(pr, None);
        assert!(!diff);
        assert_eq!(report.as_deref(), Some("out.md"));
        assert_eq!(format, "json");
    }

    #[test]
    fn audit_run_parses_branch_and_pr_flags() {
        let branch = Cli::try_parse_from(["smj", "audit", "run", "--branch", "main"]).unwrap();
        assert!(matches!(
            branch.command,
            Cmd::Audit {
                action: AuditCmd::Run { branch: Some(b), .. }
            } if b == "main"
        ));
        let pr = Cli::try_parse_from(["smj", "audit", "run", "--pr", "42"]).unwrap();
        assert!(matches!(
            pr.command,
            Cmd::Audit {
                action: AuditCmd::Run { pr: Some(p), .. }
            } if p == "42"
        ));
    }

    #[test]
    fn build_audit_params_respects_scope_precedence() {
        // pr wins over branch/path
        let params = build_audit_params(
            Some("src"),
            Some("main"),
            Some("7"),
            false,
            None,
            "md",
            None,
        );
        assert_eq!(params["pr"], "7");
        assert!(params.get("branch").is_none());
        assert!(params.get("path").is_none());

        // path scope with report + workspace
        let params = build_audit_params(
            Some("src"),
            None,
            None,
            false,
            Some("r.md"),
            "json",
            Some("/ws"),
        );
        assert_eq!(params["path"], "src");
        assert_eq!(params["report"], "r.md");
        assert_eq!(params["format"], "json");
        assert_eq!(params["workspace"], "/ws");

        // diff flag overrides a path
        let params = build_audit_params(Some("src"), None, None, true, None, "md", None);
        assert_eq!(params["diff"], true);
        assert!(params.get("path").is_none());
    }

    #[test]
    fn workspace_init_creates_dir_and_toml() {
        let dir = tempfile::tempdir().unwrap();
        cmd_workspace_init(dir.path()).unwrap();
        assert!(dir.path().join(".smedja").exists());
        let toml_content =
            std::fs::read_to_string(dir.path().join(".smedja").join("workspace.toml")).unwrap();
        assert!(toml_content.contains("auto_index = true"));
        assert!(toml_content.contains("last_indexed_at"));
    }

    #[test]
    fn auto_index_fires_when_stale() {
        let dir = tempfile::tempdir().unwrap();
        let smedja_dir = dir.path().join(".smedja");
        std::fs::create_dir_all(&smedja_dir).unwrap();
        let old_ts = (chrono::Utc::now() - chrono::Duration::hours(25)).to_rfc3339();
        let content = format!("[graph]\nauto_index = true\nlast_indexed_at = \"{old_ts}\"\n");
        std::fs::write(smedja_dir.join("workspace.toml"), &content).unwrap();
        // Verify the staleness-check logic matches what smdjad does at session.create.
        let parsed: toml::Value = toml::from_str(&content).unwrap();
        let ts_str = parsed["graph"]["last_indexed_at"].as_str().unwrap();
        let ts = chrono::DateTime::parse_from_rfc3339(ts_str).unwrap();
        let age = chrono::Utc::now().signed_duration_since(ts.with_timezone(&chrono::Utc));
        assert!(age.num_hours() >= 24, "25h old timestamp must be stale");
    }

    #[test]
    fn security_sbom_writes_cyclonedx_document() {
        let dir = tempfile::tempdir().unwrap();
        let lock = dir.path().join("Cargo.lock");
        std::fs::write(
            &lock,
            "version = 3\n\n[[package]]\nname = \"demo\"\nversion = \"1.0.0\"\n",
        )
        .unwrap();
        // Exercise the same path the CLI handler uses.
        let sbom = smedja_security::Sbom::from_lockfile(&lock).unwrap();
        let json = sbom.to_json().unwrap();
        assert!(json.contains("\"bomFormat\": \"CycloneDX\""));
        assert!(json.contains("pkg:cargo/demo@1.0.0"));
        // The handler itself returns Ok on a valid lockfile.
        super::cmd_security_sbom(&lock).unwrap();
    }

    #[test]
    fn security_report_runs_as_read_only_query() {
        let ingot = smedja_ingot::Ingot::open_in_memory().unwrap();
        // No findings recorded → the read-only query still succeeds.
        super::cmd_security_report(&ingot).unwrap();
    }

    #[test]
    fn security_scan_reports_findings_without_blocking() {
        let dir = tempfile::tempdir().unwrap();
        std::fs::write(dir.path().join(".npmrc"), "//r/:_authToken=x").unwrap();
        // Scan runs regardless of findings (advisory; never blocks).
        super::cmd_security_scan(dir.path());
        let findings = smedja_security::scan_posture(dir.path());
        assert!(findings.iter().any(|f| f.rule_id == "flagged-path"));
    }

    #[test]
    fn graph_symbols_injected_into_context() {
        // Mirrors the noun-extraction filter used by smdjad's graph auto-injection.
        let message = "implement WorkingMemory seal_prefix function";
        let stop_words = [
            "the", "and", "for", "with", "this", "that", "from", "into", "use", "are", "was",
            "has", "not", "can", "its", "will",
        ];
        let nouns: Vec<&str> = message
            .split_whitespace()
            .filter(|t| t.len() >= 3 && !stop_words.contains(&t.to_lowercase().as_str()))
            .take(5)
            .collect();
        assert!(!nouns.is_empty(), "nouns must be extracted from message");
        assert!(
            nouns.contains(&"implement")
                || nouns.contains(&"WorkingMemory")
                || nouns.contains(&"seal_prefix"),
        );
    }
}
